example.code:
resource "google_project" "app" { name = "Production App 1" project_id = "prj-prod-app1" folder_id = google_folder.production.name billing_account = var.billing_account
labels = { env = "prod" team = "platform" cost_center = "cc-001" managed_by = "terraform" }
auto_create_network = false # Disable default VPC }
# Enable required APIs resource "google_project_service" "apis" { for_each = toset([ "compute.googleapis.com", "container.googleapis.com", "cloudsql.googleapis.com", "secretmanager.googleapis.com", "monitoring.googleapis.com", "logging.googleapis.com", ])
project = google_project.app.project_id service = each.value
disable_dependent_services = false disable_on_destroy = false }
